class Solution {
    public int maxSubstrings(String word) {
        int n = word.length();
        boolean[] seen = new boolean[26];
        int count = 0;
        for (int i = 0; i < n; i++) {
            char c = word.charAt(i);
            int idx = c - 'a';
            if (seen[idx]) continue;
            seen[idx] = true;
            int j = i + 3;
            while (j < n && word.charAt(j) != c) j++;
            if (j < n) count++;
        }
        return count;
    }
}
